#include <iostream>#include <set>using namespace std; int main(){    multiset<int> o;    int n,q;    cin>>n>>q;        for(int i=0;i<n;i++)    {        int x;        cin>>x;        o.insert(x);    }        while(q--)    {        int k;        cin>>k;        if(k>0)        {            o.insert(k);        }        else        {            auto it=o.begin();            for(int i=1;i<-k;i++)            {                it++;            }            o.erase(it);        }    }        if(o.empty())    {        cout<<0<<"\n";    }    else    {        cout<<*o.begin()<<"\n";    }    return 0;}